package main

import (
	"html"
	"log"
	"net/http"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Log search event for analytics purposes
	log.Printf("Analytics: Search keyword=%q, User IP=%s", keyword, r.RemoteAddr)

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape keyword to prevent Cross-Site Scripting (XSS) attacks
	escapedKeyword := html.EscapeString(keyword)

	// Construct safe HTML response
	response := "<!DOCTYPE html>\n<html>\n<head>\n<title>Product Search Results</title>\n</head>\n<body>\n"
	response += "<h2>Search Results: " + escapedKeyword + "</h2>\n"
	response += "</body>\n</html>"

	w.Write([]byte(response))
}

func main() {
	// Register the search handler with the HTTP router
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	log.Println("Server running on http://localhost:8080/search")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

