// HandleProductSearch processes product search requests and returns HTML results with analytics logging
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword query parameter from the request URL
	keyword := r.URL.Query().Get("keyword")

	// Log structured analytics event for search activity
	event := AnalyticsEvent{
		EventType:   "product_search",
		Keyword:     keyword,
		Timestamp:   time.Now().UTC().Format(time.RFC3339),
		RemoteAddr:  r.RemoteAddr,
		UserAgent:   r.Header.Get("User-Agent"),
		RequestPath: r.URL.Path,
	}

	// Marshal event to JSON for structured logging
	eventJSON, err := json.Marshal(event)
	if err != nil {
		log.Printf("Failed to marshal analytics event: %v", err)
	} else {
		log.Printf("Analytics Event: %s", string(eventJSON))
	}

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape keyword to prevent XSS attacks in the HTML response
	escapedKeyword := html.EscapeString(keyword)

	// Write valid HTML response with the search results title
	_, err = fmt.Fprintf(w, `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>
`, escapedKeyword)
	if err != nil {
		log.Printf("Error writing response: %v", err)
	}
}

func main() {
