package main

import (
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Log analytics data for tracking search activity
	analyticsLog := struct {
		Timestamp time.Time
		ClientIP  string
		UserAgent string
		Keyword   string
	}{
		Timestamp: time.Now(),
		ClientIP:  r.RemoteAddr,
		UserAgent: r.UserAgent(),
		Keyword:   keyword,
	}

	// Log in a structured, parseable format for analytics purposes
	log.Printf(
		"SEARCH_ANALYTICS: timestamp=%s client_ip=%s user_agent=%q keyword=%q",
		analyticsLog.Timestamp.Format(time.RFC3339),
		analyticsLog.ClientIP,
		analyticsLog.UserAgent,
		analyticsLog.Keyword,
	)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape keyword to prevent cross-site scripting (XSS) attacks
	escapedKeyword := html.EscapeString(keyword)

	// Generate valid HTML response with search results header
	htmlContent := `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: ` + escapedKeyword + `</h2>
    <!-- Product listing content can be added here in a production implementation -->
</body>
</html>
`

	// Write response to client, handle any writing errors
	_, err := w.Write([]byte(htmlContent))
	if err != nil {
		log.Printf("Failed to write response: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	// Register the search handler with the /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	log.Println("Server starting on http://localhost:8080...")
	// Start HTTP server on port 8080
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

