import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the "keyword" query parameter from the request
	keyword := r.URL.Query().Get("keyword")

	// Log analytics data for the search event
	log.Printf("Analytics: Search Keyword=%q, RemoteIP=%s, Timestamp=%s",
		keyword, r.RemoteAddr, time.Now().Format(time.RFC3339))

	// Escape the keyword to prevent XSS attacks in HTML output
	escapedKeyword := html.EscapeString(keyword)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Construct the HTML response with the required search results title
	htmlContent := fmt.Sprintf(`
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <div class="results-section">
        <p>Your search query returned 0 matching products.</p>
    </div>
</body>
</html>`, escapedKeyword)

	// Write the HTML response to the client
	_, err := w.Write([]byte(htmlContent))
	if err != nil {
		log.Printf("Error writing response: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	// Register the product search handler at the /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	log.Println("Server starting on http://localhost:8080...")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

