package main

import (
	"html"
	"log"
	"net/http"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Log analytics data for search tracking
	log.Printf("Analytics: Search query - Keyword: '%s', Remote IP: '%s', User Agent: '%s'", 
		keyword, r.RemoteAddr, r.UserAgent())

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Write the HTML response with escaped keyword to prevent XSS vulnerabilities
	response := "<!DOCTYPE html>\n<html>\n<head>\n<title>Product Search Results</title>\n</head>\n<body>\n"
	response += "<h2>Search Results: " + html.EscapeString(keyword) + "</h2>\n"
	response += "</body>\n</html>"

	w.Write([]byte(response))
}

func main() {
	// Register the search handler with the appropriate endpoint
	http.HandleFunc("/product-search", HandleProductSearch)

	// Start the HTTP server on port 8080
	log.Println("Server starting on http://localhost:8080...")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

