package main

import (
	"html"
	"log"
	"net/http"
	"time"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")
	// Escape keyword to prevent XSS attacks in HTML response
	escapedKeyword := html.EscapeString(keyword)

	// Log analytics data for search events (standard library-based)
	log.Printf(
		"Analytics: Search - Keyword: %q, Timestamp: %s, Client IP: %s, User-Agent: %s",
		keyword,
		time.Now().Format(time.RFC3339),
		r.RemoteAddr,
		r.UserAgent(),
	)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Construct HTML response with search results header
	htmlContent := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: ` + escapedKeyword + `</h2>
    <div class="search-results">
        <!-- Placeholder for product results list -->
        <p>No products found matching your query.</p>
    </div>
</body>
</html>`

	// Write response to client
	_, err := w.Write([]byte(htmlContent))
	if err != nil {
		log.Printf("Failed to send response: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	// Register search handler with HTTP router
	http.HandleFunc("/search", HandleProductSearch)

	// Start HTTP server on port 8080
	log.Println("Server starting on http://localhost:8080...")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server startup failed: %v", err)
	}
}

