package main

import (
	"html"
	"log"
	"net/http"
	"time"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Log analytics data for the search event
	log.Printf(
		"Analytics: Search - Timestamp: %s, Keyword: %q, Client IP: %s, User-Agent: %s",
		time.Now().Format(time.RFC3339),
		keyword,
		r.RemoteAddr,
		r.UserAgent(),
	)

	// Escape keyword to prevent XSS attacks in HTML output
	escapedKeyword := html.EscapeString(keyword)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Construct the HTML response with search results header
	htmlContent := `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search Results</title>
    <style>
        body { font-family: Arial, sans-serif; max-width: 800px; margin: 2rem auto; padding: 0 1rem; }
        h2 { color: #2c3e50; border-bottom: 2px solid #3498db; padding-bottom: 0.5rem; }
        .results-container { margin-top: 2rem; }
        .no-results { color: #7f8c8d; font-style: italic; }
    </style>
</head>
<body>
    <h2>Search Results: ` + escapedKeyword + `</h2>
    <div class="results-container">
        <p class="no-results">No products found matching your query. Try a different keyword!</p>
    </div>
</body>
</html>
`

	// Write the response to the client
	_, err := w.Write([]byte(htmlContent))
	if err != nil {
		log.Printf("Failed to write response: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	// Register the search handler with the /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	log.Println("Server starting on http://localhost:8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

