<head>
    <meta charset="UTF-8">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: ` + escapedKeyword + `</h2>
    <!-- Additional search results content can be added here -->
</body>
</html>
`
	_, err := w.Write([]byte(htmlResponse))
	if err != nil {
		log.Printf("Error writing response: %v", err)
	}
}

func main() {
	// Register handler with HTTP router
	http.HandleFunc("/search", HandleProductSearch)

