package main

import (
	"html/template"
	"log"
	"net/http"
	"time"
)

const searchHTMLTemplate = `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: {{.}}</h2>
    {{ if eq . "" }}
        <p>Please enter a search keyword to find products.</p>
    {{ end }}
</body>
</html>
`

var searchTemplate = template.Must(template.New("productSearch").Parse(searchHTMLTemplate))

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract search keyword from URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// Log analytics data for search request
	log.Printf(
		"Analytics: Keyword=%q, RemoteAddr=%q, UserAgent=%q, Timestamp=%s",
		keyword,
		r.RemoteAddr,
		r.UserAgent(),
		time.Now().UTC().Format(time.RFC3339),
	)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Execute template to generate response
	if err := searchTemplate.Execute(w, keyword); err != nil {
		http.Error(w, "Failed to load search results", http.StatusInternalServerError)
		log.Printf("Template execution error: %v", err)
		return
	}
}

func main() {
	// Register the search handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start HTTP server
	log.Println("Server starting on http://localhost:8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

