	"fmt"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Retrieve the keyword from the URL query parameter
	keyword := r.URL.Query().Get("keyword")
	// Escape the keyword to prevent XSS attacks in HTML output
	escapedKeyword := html.EscapeString(keyword)

	// Set the response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Construct the HTML response with the required h2 tag
	htmlResponse := fmt.Sprintf(`
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <!-- Add additional product listing content here as needed -->
</body>
</html>
`, escapedKeyword)

	// Write the response and handle any errors
	_, err := w.Write([]byte(htmlResponse))
	if err != nil {
		http.Error(w, "Failed to generate search results", http.StatusInternalServerError)
	}
}

func main() {
	// Register the handler for the search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	fmt.Println("Server starting on http://localhost:8080/search")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server startup failed: %v\n", err)
	}
}

