package main

import (
	"fmt"
	"html"
	"io"
	"log"
	"net/http"
	"strings"
	"time"
)

// HandleProductSearch handles product search requests and displays results with analytics logging
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Get the original keyword from query parameters
	originalKeyword := r.URL.Query().Get("keyword")
	// Escape keyword to prevent XSS vulnerabilities in the HTML response
	escapedKeyword := html.EscapeString(originalKeyword)

	// Perform analytics logging
	logAnalytics(originalKeyword, r)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Construct the HTML response with the search results header
	htmlResponse := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <!-- Additional product results content can be added here -->
</body>
</html>`, escapedKeyword)

	// Write the response to the client
	if _, err := io.WriteString(w, htmlResponse); err != nil {
		http.Error(w, "Failed to process request", http.StatusInternalServerError)
		log.Printf("Error writing response: %v", err)
	}
}

// logAnalytics records search event details for analytics purposes
func logAnalytics(keyword string, r *http.Request) {
	timestamp := time.Now().UTC().Format(time.RFC3339)
	clientIP := extractClientIP(r)
	userAgent := r.UserAgent()

	log.Printf(
		"Analytics: Search event - Keyword: %q, Timestamp: %s, Client IP: %s, User Agent: %q",
		keyword,
		timestamp,
		clientIP,
		userAgent,
	)
}

// extractClientIP retrieves the client's IP address, considering proxy headers
func extractClientIP(r *http.Request) string {
	// Check for X-Forwarded-For header (common in reverse proxy setups)
	xffHeader := r.Header.Get("X-Forwarded-For")
	if xffHeader != "" {
		// Split multiple IPs (comma-separated) and take the original client IP first
		parts := strings.Split(xffHeader, ",")
		if len(parts) > 0 {
			trimmedIP := strings.TrimSpace(parts[0])
			if trimmedIP != "" {
				return trimmedIP
			}
		}
	}

	// Fallback to RemoteAddr if X-Forwarded-For is not available
	remoteAddr := r.RemoteAddr
	if idx := strings.LastIndex(remoteAddr, ":"); idx != -1 {
		// Remove port number from RemoteAddr
		return remoteAddr[:idx]
	}
	return remoteAddr
}

func main() {
	// Register the search handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	serverAddr := ":8080"
	log.Printf("Starting product search server on %s...", serverAddr)
	if err := http.ListenAndServe(serverAddr, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

