// Pre-parse the HTML template once for efficiency and safety
var searchTemplate = template.Must(template.New("searchResults").Parse(`
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: {{.}}</h2>
</body>
</html>
`))

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Retrieve the search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Log analytics data for the search event (keyword, IP, timestamp)
	log.Printf("Analytics - Search Keyword: %q, Remote IP: %s, Timestamp: %s",
		keyword, r.RemoteAddr, time.Now().Format(time.RFC3339))

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Execute template to generate safe HTML response
	err := searchTemplate.Execute(w, keyword)
	if err != nil {
		log.Printf("Failed to generate search page: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}
}

func main() {
	// Register the search handler with the "/search" route
	http.HandleFunc("/search", HandleProductSearch)

	// Start HTTP server on port 8080
	log.Println("Server is starting on http://localhost:8080...")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

