import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract keyword from URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// Log analytics data for the search event
	log.Printf(
		"Analytics: Search Event - Keyword: '%s', Timestamp: '%s', Client IP: '%s', User Agent: '%s'",
		keyword,
		time.Now().Format(time.RFC3339),
		r.RemoteAddr,
		r.Header.Get("User-Agent"),
	)

	// Escape keyword to prevent XSS attacks in HTML response
	escapedKeyword := html.EscapeString(keyword)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Generate HTML response with the required h2 tag
	htmlResponse := fmt.Sprintf(`
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <!-- Additional search results content can be added here -->
</body>
</html>`, escapedKeyword)

	// Write the response to the client
	fmt.Fprint(w, htmlResponse)
}

func main() {
	// Register the search handler with the "/search" route
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	log.Println("Starting server on http://localhost:8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

