package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Reject non-GET requests
	if r.Method != http.MethodGet {
		w.Header().Set("Content-Type", "text/html; charset=utf-8")
		w.WriteHeader(http.StatusMethodNotAllowed)
		fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Method Not Allowed</title>
</head>
<body>
    <h1>405 Method Not Allowed</h1>
    <p>Only GET requests are supported for this endpoint.</p>
</body>
</html>`)
		return
	}

	// Extract search keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Log analytics data (safe for parsing with quoted strings)
	clientIP := r.RemoteAddr
	timestamp := time.Now().UTC().Format(time.RFC3339)
	log.Printf("Analytics: keyword=%q, client_ip=%q, timestamp=%s", keyword, clientIP, timestamp)

	// Escape keyword to prevent XSS attacks in HTML output
	escapedKeyword := html.EscapeString(keyword)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Generate HTML response with search results header
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`, escapedKeyword)
}

func main() {
	// Register the search handler with the HTTP router
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	log.Println("Server running on http://localhost:8080/search")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

