package main

import (
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests and includes basic analytics logging
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Allow only GET requests
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Extract search keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Perform analytics logging: track timestamp, keyword, client IP, and user agent
	analyticsLog := log.New(log.Writer(), "ANALYTICS: ", log.LstdFlags)
	analyticsLog.Printf(
		"Search event - Timestamp: %s, Keyword: %q, Remote IP: %s, User Agent: %q",
		time.Now().Format(time.RFC3339),
		keyword,
		r.RemoteAddr,
		r.UserAgent(),
	)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape keyword to prevent XSS attacks when inserting into HTML
	escapedKeyword := html.EscapeString(keyword)

	// Generate HTML response with search results header
	htmlResponse := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: ` + escapedKeyword + `</h2>
    <!-- Product results list would be inserted here in a real implementation -->
</body>
</html>`

	// Write the response to the client
	if _, err := w.Write([]byte(htmlResponse)); err != nil {
		log.Printf("Failed to write response: %v", err)
	}
}

func main() {
	// Register the search handler at /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start HTTP server on port 8080
	log.Println("Server starting on http://localhost:8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

